class Solution:
    def canMakeSquare(self, grid: List[List[str]]) -> bool:
        # Check all 2x2 squares in the 3x3 grid
        for i in range(2):
            for j in range(2):
                # Extract the 2x2 square
                square = [
                    [grid[i][j], grid[i][j+1]],
                    [grid[i+1][j], grid[i+1][j+1]]
                ]
                # Count 'B' and 'W'
                b_count = sum(row.count('B') for row in square)
                w_count = 4 - b_count
                # If either count is 4 or can be made 4 by changing one cell
                if b_count == 4 or w_count == 4 or b_count == 3 or w_count == 3:
                    return True
        return False
